Here's a modern MSTest test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    [TestMethod]
    public async Task FetchAsync_ReturnsContent_WhenResponseIsSuccess()
    {
        var handler = new MockHttpMessageHandler("expected content", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        string result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("expected content", result);
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenResponseIsNotSuccess()
    {
        var handler = new MockHttpMessageHandler("", HttpStatusCode.InternalServerError);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            () => fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_Throws_WhenCancelled()
    {
        var handler = new MockHttpMessageHandler("ok", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel();

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            () => fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // fails the test if it hangs beyond 5s
    public async Task FetchAsync_CompletesWithinTimeout()
    {
        var handler = new MockHttpMessageHandler("fast", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        string result = await fetcher.FetchAsync("https://example.com");

        Assert.AreEqual("fast", result);
    }

    // Reusable fake handler — no mocking library needed
    private sealed class MockHttpMessageHandler(
        string content, HttpStatusCode statusCode) : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            var response = new HttpResponseMessage(statusCode)
            {
                Content = new StringContent(content)
            };
            return Task.FromResult(response);
        }
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---|---|
| **Async tests** | Return `async Task` — MSTest awaits them natively |
| **Timeout guard** | `[Timeout(5000)]` fails if the test hangs |
| **Cancellation** | Pre-cancel a `CancellationTokenSource`, assert `TaskCanceledException` |
| **Exception assertion** | `Assert.ThrowsExactlyAsync<T>` (MSTest v3.8+) for precise type matching |
| **No mocking library** | Custom `HttpMessageHandler` — the standard seam for `HttpClient` |

> **Note:** `ThrowsExactlyAsync` matches the exact exception type (not subclasses). If you're on an older MSTest version, use `ThrowsExceptionAsync` instead.
